const models = $input.all()
  .map((item) => item.json)
  .sort((a, b) => (b.workerCount || 0) - (a.workerCount || 0));

if (models.length === 0) {
  throw new Error('No Sogni LLM models are available right now. Try again later.');
}

const triggerJson = $('Ask For Person Name').first().json || {};
const personName = String(
  triggerJson.personName ??
  triggerJson['Person Name'] ??
  triggerJson.body?.personName ??
  triggerJson.body?.['Person Name'] ??
  triggerJson.formData?.personName ??
  triggerJson.formData?.['Person Name'] ??
  ''
).trim();

if (!personName) {
  throw new Error(`Person name is required. Trigger keys seen: ${Object.keys(triggerJson).join(', ') || '(none)'}`);
}

const bestModel = models[0];

return {
  json: {
    personName,
    modelId: bestModel.id,
    modelName: bestModel.label || bestModel.id,
    workerCount: bestModel.workerCount || 0,
    prompt: `Write a short witty rhyming poem about ${personName}. Keep it to six lines or fewer, clever, warm, and email-friendly. Mention the person by name.`,
    systemPrompt: 'You are a concise poet. Reply in plain text only with the poem. No title, no markdown, no preamble, no closing signature.'
  }
};

const poem = String($json.content || '').trim();

if (!poem) {
  throw new Error('The Sogni LLM response was empty.');
}

const personName = String($json.personName || 'this person');
const modelId = String($json.modelId || 'unknown-model');
const poemWithBreaks = poem.replace(/\n/g, '<br>');

return {
  json: {
    ...$json,
    completionTitle: `Poem for ${personName}`,
    completionMessage: `${poemWithBreaks}<br><br><small>Model: ${modelId}</small>`
  }
};
